import{_ as e,o,c as s,a2 as i}from"./chunks/framework.CuteRReP.js";const p=JSON.parse('{"title":"cro-methodology","description":"CRO audit and A/B test methodology — evidence-based conversion rate optimization using the CRE Methodology. Funnel mapping, persuasion assets, objection handling.","frontmatter":{"title":"cro-methodology","description":"CRO audit and A/B test methodology — evidence-based conversion rate optimization using the CRE Methodology. Funnel mapping, persuasion assets, objection handling.","keywords":["cro-methodology","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cro-methodology.md","filePath":"skills/cro-methodology.md"}'),r={name:"skills/cro-methodology.md"};function n(a,t,d,l,c,u){return o(),s("div",null,[...t[0]||(t[0]=[i('<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="cro-methodology" tabindex="-1">CRO Methodology <a class="header-anchor" href="#cro-methodology" aria-label="Permalink to &quot;CRO Methodology&quot;">​</a></h1><p>Scientific, customer-centric approach to conversion rate optimization based on the CRE Methodology(TM). Extraordinary improvements come from understanding WHY visitors don&#39;t convert, not from copying competitors or applying generic tips.</p><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><p><strong>Don&#39;t guess -- discover.</strong> The methodology rejects &quot;best practices&quot; and &quot;magic buttons&quot; in favor of evidence-based optimization. Most websites underperform not because of bad design, but because no one has systematically researched why visitors leave without converting.</p><p><strong>The foundation:</strong> Every visitor who doesn&#39;t convert has a reason. Your job is to discover those reasons through research, then systematically eliminate them with evidence and proof. This customer-centric approach consistently outperforms intuition, competitor copying, and &quot;expert&quot; opinions.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p><strong>Goal: 10/10.</strong> When reviewing or creating landing pages, funnels, or conversion flows, rate them 0-10 based on adherence to the principles below. A 10/10 means full alignment with all guidelines; lower scores indicate gaps to address. Always provide the current score and specific improvements needed to reach 10/10.</p><h2 id="the-cro-frameworks" tabindex="-1">The CRO Frameworks <a class="header-anchor" href="#the-cro-frameworks" aria-label="Permalink to &quot;The CRO Frameworks&quot;">​</a></h2><h3 id="_1-the-cro-process" tabindex="-1">1. The CRO Process <a class="header-anchor" href="#_1-the-cro-process" aria-label="Permalink to &quot;1. The CRO Process&quot;">​</a></h3><p><strong>Core concept:</strong> A systematic 9-step process for optimizing conversion rates, moving from defining success metrics through research, experimentation, and scaling wins across the business.</p><p><strong>Why it works:</strong> Random optimization efforts fail because they skip the critical research steps. The CRE process forces you to understand visitors before changing anything, ensuring changes are based on evidence rather than opinion.</p><p><strong>Key insights:</strong></p><ul><li>Define success metrics aligned with business KPIs before touching any page</li><li>Map the entire conversion funnel to find &quot;blocked arteries&quot; (high-traffic underperforming paths) and &quot;missing links&quot; (absent funnel stages)</li><li>Understand visitors in three dimensions: who they are (types and intentions), what blocks them (UX problems), and what stops them (objections)</li><li>Gather market intelligence from competitors, reviews, and other industries</li><li>Prioritize ideas using ICE scoring (Impact, Confidence, Ease) before testing</li><li>Create bold experimental designs based on research, not &quot;meek tweaks&quot;</li><li>Run experiments with proper statistical rigor (95% confidence minimum, full business cycles)</li><li>Scale wins across landing pages, ad copy, email sequences, and offline materials</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>CRO Process Step</th><th>Example</th></tr></thead><tbody><tr><td><strong>Landing page audit</strong></td><td>Steps 1-3: Define goals, map funnel, research visitors</td><td>Identify that 70% of traffic bounces because value prop is unclear</td></tr><tr><td><strong>Checkout optimization</strong></td><td>Step 2: Map funnel for blocked arteries</td><td>Discover shipping cost shock causes 40% cart abandonment</td></tr><tr><td><strong>New feature launch</strong></td><td>Steps 6-8: Strategize, design, experiment</td><td>A/B test two positioning approaches before full rollout</td></tr><tr><td><strong>Email sequence</strong></td><td>Step 9: Scale wins</td><td>Apply winning objection-handling copy from landing page to drip emails</td></tr><tr><td><strong>Competitor response</strong></td><td>Step 4: Market intelligence</td><td>Transfer proven strategies from adjacent industries</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;What&#39;s preventing you from [action] today?&quot; (exit survey question to discover objections)</li><li>&quot;Here&#39;s what [X] customers found...&quot; (counter-objection with social proof)</li><li>Document hypothesis: &quot;If we [change X], then [metric Y] will improve because [reason from research]&quot;</li><li>Always calculate required sample size BEFORE starting any test</li></ul><p><strong>Ethical boundary:</strong> Never manipulate test results or cherry-pick data. Report all tests, including failures, and wait for genuine statistical significance.</p><p>See: <a href="./references/testing-methodology">testing-methodology.md</a> for detailed ICE scoring, A/B vs. multivariate guidance, and statistical rigor.</p><h3 id="_2-customer-research-objections" tabindex="-1">2. Customer Research &amp; Objections <a class="header-anchor" href="#_2-customer-research-objections" aria-label="Permalink to &quot;2. Customer Research &amp; Objections&quot;">​</a></h3><p><strong>Core concept:</strong> Visitors don&#39;t convert for specific, discoverable reasons. Research methods -- exit surveys, chat logs, support tickets, sales calls, reviews -- reveal the &quot;voice of the customer&quot; and their real objections.</p><p><strong>Why it works:</strong> Companies guess why visitors leave, but guesses are almost always wrong. Direct research consistently uncovers objections that teams never anticipated, and the language customers use is more persuasive than any copywriter&#39;s invention.</p><p><strong>Key insights:</strong></p><ul><li>Primary sources (exit surveys, live chat logs, support tickets, sales call recordings) give you direct visitor language</li><li>Secondary sources (reviews, social media, competitor analysis) reveal industry-wide objections</li><li>Objections fall into two categories: explicit (&quot;too expensive&quot;) and implicit (&quot;I&#39;m not sure I&#39;ll follow through&quot;)</li><li>The &quot;Big 5&quot; universal objections are Trust, Price, Fit, Timing, and Effort</li><li>Post-purchase surveys (&quot;What almost stopped you from buying?&quot;) reveal the objections that matter most</li><li>Non-converter surveys should ask ONE question for maximum response rate</li><li>Quantitative research (analytics, heatmaps) shows WHERE problems are; qualitative research (surveys, interviews) shows WHY</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Research Method</th><th>Example</th></tr></thead><tbody><tr><td><strong>Exit intent</strong></td><td>On-site survey (Hotjar, Qualaroo)</td><td>&quot;What&#39;s preventing you from signing up today?&quot;</td></tr><tr><td><strong>Post-purchase</strong></td><td>Email survey within 7 days</td><td>&quot;What almost stopped you from buying?&quot;</td></tr><tr><td><strong>Objection mining</strong></td><td>Support ticket analysis</td><td>Search for &quot;but&quot;, &quot;however&quot;, &quot;worried about&quot; patterns</td></tr><tr><td><strong>Voice of customer</strong></td><td>Sales call recordings</td><td>Capture exact language customers use to describe problems</td></tr><tr><td><strong>Competitive gaps</strong></td><td>Review mining (yours and competitors&#39;)</td><td>Negative reviews = unaddressed objections</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>Use exact customer language in headlines and body copy (more persuasive than polished marketing copy)</li><li>&quot;What&#39;s the one thing we could change to make you [action]?&quot;</li><li>&quot;How would you describe [product] to a friend?&quot; (reveals positioning in customer terms)</li><li>Ask open-ended questions for discovery; save multiple choice for validation</li></ul><p><strong>Ethical boundary:</strong> Respect customer privacy in research. Anonymize data, get consent for recordings, and don&#39;t survey so aggressively that you degrade the user experience.</p><p>See: <a href="./references/RESEARCH">RESEARCH.md</a> for tools, survey questions, and data analysis methods.</p><h3 id="_3-persuasion-assets" tabindex="-1">3. Persuasion Assets <a class="header-anchor" href="#_3-persuasion-assets" aria-label="Permalink to &quot;3. Persuasion Assets&quot;">​</a></h3><p><strong>Core concept:</strong> Every company has overlooked proof elements -- testimonials not displayed, awards not mentioned, statistics not highlighted, guarantees not prominent, team credentials hidden. These are &quot;persuasion assets&quot; that must be inventoried, acquired, and displayed.</p><p><strong>Why it works:</strong> Visitors make decisions based on evidence and proof, not claims. A bold claim without proof is just noise. A modest claim with overwhelming proof is irresistible. Most companies sit on goldmines of proof they never use.</p><p><strong>Key insights:</strong></p><ul><li>Audit five categories: Credentials &amp; Authority, Social Proof, Risk Reversal, Data &amp; Specificity, Process &amp; Methodology</li><li>Create a &quot;wish list&quot; for missing assets and actively acquire them (request testimonials, apply for awards, compile statistics)</li><li>The &quot;proof sandwich&quot; structure: Claim (bold promise) then Proof (evidence) then Reinforcement (secondary proof)</li><li>Hierarchy of proof from strongest to weakest: specific results with context, named testimonials with photos, case studies, statistics, logos/badges, generic testimonials</li><li>Place proof at points of friction, not hidden in FAQs</li><li>Specific numbers beat round numbers (&quot;47,832 customers&quot; beats &quot;About 50,000&quot;)</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Persuasion Asset</th><th>Example</th></tr></thead><tbody><tr><td><strong>Landing page header</strong></td><td>Logo bar + rating</td><td>&quot;Trusted by 10,000+ companies&quot; with 5 recognizable logos</td></tr><tr><td><strong>Pricing page</strong></td><td>Risk reversal</td><td>&quot;30-day money-back guarantee, no questions asked&quot;</td></tr><tr><td><strong>Product page</strong></td><td>Specific testimonial</td><td>Photo + name + company + &quot;Increased conversion by 47% in 3 weeks&quot;</td></tr><tr><td><strong>Checkout flow</strong></td><td>Trust badges near forms</td><td>Security certification, payment logos, guarantee seal</td></tr><tr><td><strong>About page</strong></td><td>Team credentials</td><td>Years of experience, certifications, publications, patents</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Here&#39;s how we did it for [Company X]...&quot; (case study proof)</li><li>&quot;And here&#39;s what their CEO says about working with us...&quot; (testimonial reinforcement)</li><li>&quot;[Specific number] businesses trust us&quot; (not &quot;thousands of customers&quot;)</li><li>Lead with benefits, not features: &quot;Never delete another photo&quot; beats &quot;256GB storage&quot;</li></ul><p><strong>Ethical boundary:</strong> Never fabricate testimonials, inflate statistics, or display fake trust badges. All proof must be genuine and verifiable.</p><p>See: <a href="./references/PERSUASION">PERSUASION.md</a> for the full persuasion assets checklist and psychological triggers.</p><h3 id="_4-the-o-co-framework" tabindex="-1">4. The O/CO Framework <a class="header-anchor" href="#_4-the-o-co-framework" aria-label="Permalink to &quot;4. The O/CO Framework&quot;">​</a></h3><p><strong>Core concept:</strong> The Objection/Counter-Objection (O/CO) table is the core CRE technique. Create a two-column table mapping every visitor objection to specific, evidence-backed counter-objections.</p><p><strong>Why it works:</strong> Visitors arrive with objections. If the page doesn&#39;t address them, visitors leave. The O/CO framework ensures no objection goes unanswered, and counter-objections are placed exactly where objections naturally arise during the reading flow.</p><p><strong>Key insights:</strong></p><ul><li>Don&#39;t guess objections -- research them from surveys, chat logs, support tickets, and sales calls</li><li>Implicit objections (ones visitors won&#39;t admit) require &quot;CO Only&quot; approach: address the objection without stating it</li><li>Place counter-objections at the point of friction (credit card objection near payment form), not buried in FAQ</li><li>Address primary objections above the fold, secondary objections in the flow</li><li>Use multiple formats for the same counter-objection: text, video, testimonial, data</li><li>Canned support responses are goldmines of tested counter-objections</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Objection Type</th><th>O/CO Example</th></tr></thead><tbody><tr><td><strong>Trust</strong></td><td>&quot;Why should I believe you?&quot;</td><td>Specific testimonials, media logos, awards, money-back guarantee</td></tr><tr><td><strong>Price</strong></td><td>&quot;Is it worth the money?&quot;</td><td>ROI calculator, cost comparison vs. alternatives, payment plans</td></tr><tr><td><strong>Fit</strong></td><td>&quot;Will it work for MY situation?&quot;</td><td>Case studies from similar customers, segmented landing pages, free trial</td></tr><tr><td><strong>Timing</strong></td><td>&quot;Why should I act now?&quot;</td><td>Cost of delay calculation, genuine limited-time offers, seasonal relevance</td></tr><tr><td><strong>Effort</strong></td><td>&quot;How hard will this be?&quot;</td><td>&quot;Done for you&quot; framing, &quot;Set up in 5 minutes&quot;, step-by-step breakdown</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>Bad (stating implicit objection): &quot;Worried you&#39;re too lazy to learn a language?&quot;</li><li>Good (CO Only): &quot;Let the audio do the work for you.&quot;</li><li>&quot;What&#39;s preventing you from signing up today?&quot; (survey to discover objections)</li><li>&quot;What almost stopped you from buying?&quot; (post-purchase survey to validate O/CO table)</li></ul><p><strong>Ethical boundary:</strong> Address real objections with honest counter-objections. Never dismiss legitimate concerns or use deception to overcome valid hesitations.</p><p>See: <a href="./references/OBJECTIONS">OBJECTIONS.md</a> for the full O/CO framework, research methods, and counter-objection techniques.</p><h3 id="_5-hypothesis-design" tabindex="-1">5. Hypothesis Design <a class="header-anchor" href="#_5-hypothesis-design" aria-label="Permalink to &quot;5. Hypothesis Design&quot;">​</a></h3><p><strong>Core concept:</strong> Every experiment needs a documented hypothesis linking a specific change to an expected outcome with a reason grounded in research. Prioritize using ICE scoring (Impact, Confidence, Ease).</p><p><strong>Why it works:</strong> Without a hypothesis, you&#39;re just changing things randomly. The hypothesis forces you to articulate WHY a change should work, which means it must be grounded in customer research. ICE scoring prevents teams from wasting time on low-impact &quot;meek tweaks.&quot;</p><p><strong>Key insights:</strong></p><ul><li>Hypothesis format: &quot;If we [change X], then [metric Y] will improve because [reason based on research]&quot;</li><li>Define primary metric (determines winner), secondary metrics (additional monitoring), and guardrail metrics (must not decrease)</li><li>ICE scores: Impact (1-10: could this double conversion?), Confidence (1-10: is research backing strong?), Ease (1-10: how easy to implement?)</li><li>Make BOLD changes, not &quot;meek tweaks&quot; -- small changes rarely reach statistical significance and waste resources</li><li>Before testing, ask: &quot;Could this 10x our results?&quot; If not, reconsider priority</li><li>Worth testing: complete page redesign, new value proposition, fundamentally different offer</li><li>Not worth testing: button color, font size, image swap</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Hypothesis Example</th><th>ICE Score</th></tr></thead><tbody><tr><td><strong>Headline rewrite</strong></td><td>&quot;If we use customer language from surveys, conversion will increase because visitors see their own words reflected&quot;</td><td>I:8, C:9, E:10 = 9.0</td></tr><tr><td><strong>Video testimonial</strong></td><td>&quot;If we add video testimonial addressing price objection, signups will increase because visitors need trust proof&quot;</td><td>I:7, C:7, E:6 = 6.7</td></tr><tr><td><strong>Checkout redesign</strong></td><td>&quot;If we simplify checkout to one page, completion will increase because analytics show 40% drop at step 2&quot;</td><td>I:9, C:6, E:3 = 6.0</td></tr><tr><td><strong>Button color</strong></td><td>&quot;If we change button from blue to green, clicks will increase because green means go&quot;</td><td>I:2, C:2, E:10 = 4.7</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Based on our research, visitors&#39; #1 objection is [X]. This test addresses it by [Y].&quot;</li><li>Document before: hypothesis, primary metric, sample size, duration, traffic allocation</li><li>Document after: raw numbers, confidence interval, practical significance, learnings, next steps</li><li>Every test adds to organizational knowledge regardless of outcome</li></ul><p><strong>Ethical boundary:</strong> Report all test results honestly, including failures. Never cherry-pick data or run tests until you get the result you want.</p><p>See: <a href="./references/testing-methodology">testing-methodology.md</a> for ICE scoring tables and detailed prioritization.</p><h3 id="_6-a-b-testing-methodology" tabindex="-1">6. A/B Testing Methodology <a class="header-anchor" href="#_6-a-b-testing-methodology" aria-label="Permalink to &quot;6. A/B Testing Methodology&quot;">​</a></h3><p><strong>Core concept:</strong> Run controlled experiments comparing page versions to determine which performs better, using proper statistical rigor to ensure results are real, not random noise.</p><p><strong>Why it works:</strong> Without controlled experiments, you can&#39;t distinguish real improvements from random variation. Proper A/B testing methodology prevents the most common errors: peeking and stopping early, insufficient sample size, ignoring practical significance, and the multiple comparison problem.</p><p><strong>Key insights:</strong></p><ul><li>Calculate required sample size BEFORE starting (inputs: baseline rate, minimum detectable effect, 80% power, 95% significance)</li><li>Run for at least one full business cycle (1-2 weeks) including weekdays AND weekends</li><li>Never peek at results and stop early -- this inflates false positive rates dramatically</li><li>95% confidence minimum (p-value less than 0.05) before calling a winner</li><li>A statistically significant 0.1% lift isn&#39;t worth implementation complexity (practical significance matters)</li><li>Start with A/B tests; only move to multivariate when you have 100k+ monthly visitors and a proven winning page</li><li>A failed test that teaches you something is more valuable than a winning test you don&#39;t understand</li><li>Promote winners to new control and iterate</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Test Type</th><th>Example</th></tr></thead><tbody><tr><td><strong>Concept validation</strong></td><td>A/B test (2-4 variants)</td><td>Test two fundamentally different page layouts based on different customer insights</td></tr><tr><td><strong>Element optimization</strong></td><td>Multivariate (100k+ visitors)</td><td>Test 3 headlines x 3 images x 2 CTAs on proven winning page</td></tr><tr><td><strong>Low traffic</strong></td><td>Bold A/B test</td><td>Make dramatic changes detectable with smaller samples (~4,000 visitors for 50% lift)</td></tr><tr><td><strong>High traffic</strong></td><td>Rapid iteration</td><td>Run parallel tests on non-overlapping pages, 10-20 tests/month</td></tr><tr><td><strong>Post-test</strong></td><td>Scale wins</td><td>Apply winning insights across landing pages, ad copy, email sequences</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;We increased [metric] by [X]% with [Y]% confidence over [Z] weeks&quot;</li><li>&quot;Test showed no significant difference, teaching us that [insight about customers]&quot;</li><li>&quot;Control outperformed challenger, suggesting visitors prefer [existing approach] because [reason]&quot;</li><li>Always document learnings: Test, Hypothesis, Result, Learning, Applicable to</li></ul><p><strong>Ethical boundary:</strong> Never manipulate statistical methods to manufacture significance. Report confidence intervals honestly and acknowledge when results are inconclusive.</p><p>See: <a href="./references/testing-methodology">testing-methodology.md</a> for statistical significance, sample size calculations, and platform comparison.</p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Why It Fails</th><th>Fix</th></tr></thead><tbody><tr><td><strong>Copying competitors blindly</strong></td><td>You don&#39;t know if their approach works for them, let alone for you</td><td>Research YOUR visitors&#39; objections and build YOUR evidence</td></tr><tr><td><strong>Testing button colors before understanding objections</strong></td><td>Addresses surface symptoms, not root causes; tiny effects waste sample size</td><td>Do customer research first, then test big changes based on findings</td></tr><tr><td><strong>Assuming you know why visitors leave</strong></td><td>Teams are almost always wrong about visitor motivations</td><td>Use exit surveys, chat logs, and support analysis to discover real reasons</td></tr><tr><td><strong>Using &quot;best practices&quot; without validation</strong></td><td>What works elsewhere may not work for your audience, product, or context</td><td>Treat best practices as hypotheses to test, not rules to follow</td></tr><tr><td><strong>Making decisions based on HiPPO</strong></td><td>Highest Paid Person&#39;s Opinion is not data; authority bias kills optimization</td><td>Let research and test results determine changes, not seniority</td></tr><tr><td><strong>Optimizing pages without funnel context</strong></td><td>Improving one step may shift problems to another; miss biggest opportunities</td><td>Map entire funnel first, identify blocked arteries, prioritize by impact</td></tr><tr><td><strong>Making &quot;meek tweaks&quot; instead of bold changes</strong></td><td>Small changes rarely reach statistical significance; wastes time and traffic</td><td>Test changes that could double conversion, not nudge it 2%</td></tr><tr><td><strong>Giving up after one failed test</strong></td><td>The opportunity still exists; you just haven&#39;t found the solution yet</td><td>Investigate why, go back to research, try a bolder change</td></tr></tbody></table><h2 id="quick-diagnostic" tabindex="-1">Quick Diagnostic <a class="header-anchor" href="#quick-diagnostic" aria-label="Permalink to &quot;Quick Diagnostic&quot;">​</a></h2><p>Audit any landing page or conversion flow:</p><table tabindex="0"><thead><tr><th>Question</th><th>If No</th><th>Action</th></tr></thead><tbody><tr><td>Do we know the ONE action visitors should take on this page?</td><td>Page lacks focus, visitors are confused</td><td>Define single primary conversion goal and remove competing CTAs</td></tr><tr><td>Have we researched why visitors aren&#39;t converting (not guessed)?</td><td>Optimization is based on assumptions, not evidence</td><td>Run exit surveys, analyze chat logs, review support tickets</td></tr><tr><td>Do we have an O/CO table mapping objections to counter-objections?</td><td>Visitor objections go unanswered on the page</td><td>Build O/CO table from research, place counter-objections at friction points</td></tr><tr><td>Is the value proposition crystal clear within 5 seconds?</td><td>Visitors bounce before understanding the offer</td><td>Run 5-second test, rewrite headline using customer language</td></tr><tr><td>Are persuasion assets visible (testimonials, awards, guarantees)?</td><td>Page makes claims without proof, visitors don&#39;t believe</td><td>Audit persuasion assets, acquire missing ones, display prominently</td></tr><tr><td>Have we mapped the full funnel and identified blocked arteries?</td><td>Optimizing wrong page or missing biggest opportunity</td><td>Map traffic volume at each stage, compare to benchmarks, prioritize by impact</td></tr></tbody></table><h2 id="quick-start-checklist" tabindex="-1">Quick-Start Checklist <a class="header-anchor" href="#quick-start-checklist" aria-label="Permalink to &quot;Quick-Start Checklist&quot;">​</a></h2><p>When optimizing any page:</p><ol><li>[ ] What is the ONE action visitors should take?</li><li>[ ] Who are the visitors? What stage of buying journey?</li><li>[ ] What are their top 3-5 objections? (Don&#39;t guess -- research)</li><li>[ ] What proof/counter-objections address each?</li><li>[ ] Is the value proposition crystal clear in 5 seconds?</li><li>[ ] Are there UX blockers? (speed, mobile, forms)</li><li>[ ] What persuasion assets are missing or hidden?</li></ol><h2 id="reference-files" tabindex="-1">Reference Files <a class="header-anchor" href="#reference-files" aria-label="Permalink to &quot;Reference Files&quot;">​</a></h2><ul><li><a href="./references/OBJECTIONS">OBJECTIONS.md</a>: O/CO framework, research methods, counter-objection techniques</li><li><a href="./references/COPYWRITING">COPYWRITING.md</a>: Headlines, proof elements, persuasive writing</li><li><a href="./references/PERSUASION">PERSUASION.md</a>: Persuasion assets checklist, psychological triggers</li><li><a href="./references/RESEARCH">RESEARCH.md</a>: Tools, survey questions, data analysis</li><li><a href="./references/testing-methodology">testing-methodology.md</a>: A/B testing, statistical significance, ICE prioritization, multivariate testing</li><li><a href="./references/funnel-analysis">funnel-analysis.md</a>: Blocked arteries, missing links, industry funnels, cross-sell mapping</li></ul><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><p>This skill is based on the CRE Methodology(TM) developed by Conversion Rate Experts. For the complete methodology, detailed case studies, and advanced techniques, read the original book:</p><ul><li><a href="https://www.amazon.com/Making-Websites-Win-Customer-Centric-Methodology/dp/1544500513" target="_blank" rel="noreferrer"><em>&quot;Making Websites Win: Apply the Customer-Centric Methodology That Has Doubled the Sales of Many Leading Websites&quot;</em></a> by Dr. Karl Blanks and Ben Jesson</li></ul><h2 id="about-the-author" tabindex="-1">About the Author <a class="header-anchor" href="#about-the-author" aria-label="Permalink to &quot;About the Author&quot;">​</a></h2><p><strong>Dr. Karl Blanks and Ben Jesson</strong> are the cofounders of Conversion Rate Experts (CRE), the world&#39;s leading agency specializing in conversion rate optimization. Their clients have included Google, Apple, Amazon, Facebook, Dropbox, and many other technology leaders. CRE&#39;s methodology has been recognized with a Queen&#39;s Award for Enterprise (Innovation), the UK&#39;s highest business honor. Blanks holds a PhD in user experience and previously managed teams of usability researchers at Hewlett-Packard. Jesson&#39;s background is in direct-response marketing and web development. Together they developed the CRE Methodology, which has been applied across hundreds of websites and consistently delivered significant conversion improvements. Their book <em>Making Websites Win</em> distills this methodology into a systematic, repeatable process for evidence-based website optimization.</p>',91)])])}const g=e(r,[["render",n]]);export{p as __pageData,g as default};
